import{o as s,c as a,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Quick start guide","description":"Quickly start a chain node using the Testapp CLI.","frontmatter":{"title":"Quick start guide","description":"Quickly start a chain node using the Testapp CLI.","head":[["meta",{"name":"og:title","content":"Quick start guide | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/quick-start.md","filePath":"guides/quick-start.md","lastUpdated":1779645806000}'),l={name:"guides/quick-start.md"},e=Object.assign(l,{setup:o=>(o,l)=>(s(),a("div",null,[...l[0]||(l[0]=[n('<h1 id="quick-start-guide" tabindex="-1">Quick start guide <a class="header-anchor" href="#quick-start-guide" aria-label="Permalink to &quot;Quick start guide&quot;">​</a></h1><p>Welcome to Evolve, a chain framework! The easiest way to launch your network node is by using the Testapp CLI.</p><h2 id="📦-install-testapp-cli" tabindex="-1">📦 Install Testapp (CLI) <a class="header-anchor" href="#📦-install-testapp-cli" aria-label="Permalink to &quot;📦 Install Testapp (CLI)&quot;">​</a></h2><p>To install Evolve, run the following command in your terminal:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Clone the repository</span></span>\n<span class="line"><span style="color:#94EEFF;">git</span><span style="color:#BFF3C2;"> clone</span><span style="color:#FFECB6;"> --depth</span><span style="color:#FFECB6;"> 1</span><span style="color:#BFF3C2;"> https://github.com/evstack/ev-node.git</span></span>\n<span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ev-node</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Build the testapp binary</span></span>\n<span class="line"><span style="color:#94EEFF;">just</span><span style="color:#BFF3C2;"> build</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Optional: Install to your Go bin directory for system-wide access</span></span>\n<span class="line"><span style="color:#94EEFF;">just</span><span style="color:#BFF3C2;"> install</span></span></code></pre></div><p>Verify the installation by checking the Evolve version:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># If you ran &#39;just install&#39;</span></span>\n<span class="line"><span style="color:#94EEFF;">testapp</span><span style="color:#BFF3C2;"> version</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Or if you only ran &#39;just build&#39;</span></span>\n<span class="line"><span style="color:#94EEFF;">./build/testapp</span><span style="color:#BFF3C2;"> version</span></span></code></pre></div><p>A successful installation will display the version number and its associated git commit hash.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">evolve</span><span style="color:#BFF3C2;"> version:</span><span style="color:#BFF3C2;">  v1.0.0-beta.4</span></span></code></pre></div><h2 id="🗂️-initialize-a-evolve-network-node" tabindex="-1">🗂️ Initialize a evolve network node <a class="header-anchor" href="#🗂️-initialize-a-evolve-network-node" aria-label="Permalink to &quot;🗂️ Initialize a evolve network node&quot;">​</a></h2><p>To initialize a evolve network node, execute the following command:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">testapp</span><span style="color:#BFF3C2;"> init</span><span style="color:#FFECB6;"> --evnode.node.aggregator</span><span style="color:#FFECB6;"> --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span></span></code></pre></div><h2 id="🚀-run-your-evolve-network-node" tabindex="-1">🚀 Run your evolve network node <a class="header-anchor" href="#🚀-run-your-evolve-network-node" aria-label="Permalink to &quot;🚀 Run your evolve network node&quot;">​</a></h2><p>Now that we have our testapp generated and installed, we can launch our chain along with the local DA by running the following command:</p><p>First lets start the local DA network:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> install</span><span style="color:#BFF3C2;"> github.com/evstack/ev-node/tools/local-da@latest</span></span>\n<span class="line"><span style="color:#94EEFF;">local-da</span></span></code></pre></div><p>You should see logs like:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">9:22AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> NewLocalDA:</span><span style="color:#BFF3C2;"> initialized</span><span style="color:#BFF3C2;"> LocalDA</span><span style="color:#BFF3C2;"> component=da</span></span>\n<span class="line"><span style="color:#94EEFF;">9:22AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> Listening</span><span style="color:#BFF3C2;"> on</span><span style="color:#BFF3C2;"> component=da</span><span style="color:#BFF3C2;"> host=localhost</span><span style="color:#BFF3C2;"> maxBlobSize=</span><span style="color:#FFECB6;">1974272</span><span style="color:#BFF3C2;"> port=</span><span style="color:#FFECB6;">7980</span></span>\n<span class="line"><span style="color:#94EEFF;">9:22AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> server</span><span style="color:#BFF3C2;"> started</span><span style="color:#BFF3C2;"> component=da</span><span style="color:#BFF3C2;"> listening_on=localhost:7980</span></span></code></pre></div><p>To start a basic evolve network node, execute:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">testapp</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span></span></code></pre></div><p>Upon execution, the CLI will output log entries that provide insights into the node&#39;s initialization and operation:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> creating</span><span style="color:#BFF3C2;"> new</span><span style="color:#BFF3C2;"> client</span><span style="color:#BFF3C2;"> component=main</span><span style="color:#BFF3C2;"> namespace=</span></span>\n<span class="line"><span style="color:#94EEFF;">KV</span><span style="color:#BFF3C2;"> Executor</span><span style="color:#BFF3C2;"> HTTP</span><span style="color:#BFF3C2;"> server</span><span style="color:#BFF3C2;"> starting</span><span style="color:#BFF3C2;"> on</span><span style="color:#BFF3C2;"> 127.0.0.1:9090</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> KV</span><span style="color:#BFF3C2;"> executor</span><span style="color:#BFF3C2;"> HTTP</span><span style="color:#BFF3C2;"> server</span><span style="color:#BFF3C2;"> started</span><span style="color:#BFF3C2;"> component=main</span><span style="color:#BFF3C2;"> endpoint=127.0.0.1:9090</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> No</span><span style="color:#BFF3C2;"> state</span><span style="color:#BFF3C2;"> found</span><span style="color:#BFF3C2;"> in</span><span style="color:#BFF3C2;"> store,</span><span style="color:#BFF3C2;"> initializing</span><span style="color:#BFF3C2;"> new</span><span style="color:#BFF3C2;"> state</span><span style="color:#BFF3C2;"> component=BlockManager</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> using</span><span style="color:#BFF3C2;"> default</span><span style="color:#BFF3C2;"> mempool</span><span style="color:#BFF3C2;"> ttl</span><span style="color:#BFF3C2;"> MempoolTTL=</span><span style="color:#FFECB6;">25</span><span style="color:#BFF3C2;"> component=BlockManager</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> starting</span><span style="color:#BFF3C2;"> P2P</span><span style="color:#BFF3C2;"> client</span><span style="color:#BFF3C2;"> component=main</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> started</span><span style="color:#BFF3C2;"> RPC</span><span style="color:#BFF3C2;"> server</span><span style="color:#BFF3C2;"> addr=127.0.0.1:7331</span><span style="color:#BFF3C2;"> component=main</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> listening</span><span style="color:#BFF3C2;"> on</span><span style="color:#BFF3C2;"> address</span><span style="color:#BFF3C2;"> address=/ip4/127.0.0.1/tcp/7676/p2p/12D3KooWRzvJuFoQKhQNfaCZWvJFDY4vrCTocdL6H1GCMzywugnV</span><span style="color:#BFF3C2;"> component=main</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> listening</span><span style="color:#BFF3C2;"> on</span><span style="color:#BFF3C2;"> address</span><span style="color:#BFF3C2;"> address=/ip4/172.20.10.14/tcp/7676/p2p/12D3KooWRzvJuFoQKhQNfaCZWvJFDY4vrCTocdL6H1GCMzywugnV</span><span style="color:#BFF3C2;"> component=main</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> no</span><span style="color:#BFF3C2;"> peers</span><span style="color:#BFF3C2;"> -</span><span style="color:#BFF3C2;"> only</span><span style="color:#BFF3C2;"> listening</span><span style="color:#BFF3C2;"> for</span><span style="color:#BFF3C2;"> connections</span><span style="color:#BFF3C2;"> component=main</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> working</span><span style="color:#BFF3C2;"> in</span><span style="color:#BFF3C2;"> aggregator</span><span style="color:#BFF3C2;"> mode</span><span style="color:#BFF3C2;"> block_time=</span><span style="color:#FFECB6;">1000</span><span style="color:#BFF3C2;"> component=main</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> using</span><span style="color:#BFF3C2;"> pending</span><span style="color:#BFF3C2;"> block</span><span style="color:#BFF3C2;"> component=BlockManager</span><span style="color:#BFF3C2;"> height=</span><span style="color:#FFECB6;">1</span></span>\n<span class="line"><span style="color:#94EEFF;">9:23AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> Reaper</span><span style="color:#BFF3C2;"> started</span><span style="color:#BFF3C2;"> component=Reaper</span><span style="color:#BFF3C2;"> interval=</span><span style="color:#FFECB6;">1000</span></span></code></pre></div><h2 id="🎉-conclusion" tabindex="-1">🎉 Conclusion <a class="header-anchor" href="#🎉-conclusion" aria-label="Permalink to &quot;🎉 Conclusion&quot;">​</a></h2><p>That&#39;s it! Your evolve network node is now up and running. It&#39;s incredibly simple to start a blockchain (which is essentially what a chain is) these days using Evolve. Explore further and discover how you can build useful applications on Evolve. Good luck!</p>',24)])]))});export{o as __pageData,e as default};
